('spanish:3-2-future-study-jobs-and-ambitions:tips:cb403af6', 'spanish', 'spanish:3-2-future-study-jobs-and-ambitions', '3.2 Future Study, Jobs and Ambitions', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Listening for job vocabulary", "reading": "Job vocabulary is everywhere in Paper 1. Listen for the ending of the job noun (-o masculine, -a feminine: ingeniero/ingeniera) and for whether the tense is quiero ser (ambition), soy (current job) or voy a (near-future plan).", "question": "You hear ‘Quiero ser ingeniera’. What does this tell you?", "options": ["The speaker (female) wants to be an engineer", "The speaker (male) wants to be an engineer instead", "The speaker (female) wants to be a teacher one day", "The speaker (male) already works as an engineer eventually"]}'::jsonb, '{"answer": 0, "explain": "‘ingeniera’ (-a ending) signals a female speaker; ‘quiero ser’ = I want to be (an ambition, not a current job)."}'::jsonb),
